# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated for multiple URLs),
    fetches data from those URLs, and adds the enrichment data as headers
    before forwarding to origin.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Check for the X-Enrich-URL header
    enrich_header_key = 'x-enrich-url'
    
    if enrich_header_key not in headers:
        # No enrichment requested, pass through
        return request
    
    # Extract all enrichment URLs (could be multiple header values or comma-separated)
    enrich_urls = []
    for header_entry in headers[enrich_header_key]:
        urls = header_entry.get('value', '')
        for url in urls.split(','):
            stripped = url.strip()
            if stripped:
                enrich_urls.append(stripped)
    
    if not enrich_urls:
        return request
    
    # Fetch data from each enrichment URL
    enrichment_results = {}
    errors = []
    
    for idx, url in enumerate(enrich_urls):
        try:
            # Validate URL scheme - only allow http and https
            if not url.startswith(('http://', 'https://')):
                errors.append({
                    'url': url,
                    'error': 'Invalid URL scheme. Only http and https are allowed.'
                })
                continue
            
            # Create request with timeout to avoid Lambda@Edge timeout issues
            req = urllib.request.Request(
                url,
                method='GET',
                headers={
                    'User-Agent': 'LambdaEdge-Enrichment/1.0',
                    'Accept': 'application/json, text/plain, */*'
                }
            )
            
            # Fetch with a short timeout (Lambda@Edge viewer request has 5s limit)
            with urllib.request.urlopen(req, timeout=2) as response:
                status_code = response.getcode()
                response_body = response.read().decode('utf-8', errors='replace')
                content_type = response.getheader('Content-Type', '')
                
                # Try to parse as JSON
                try:
                    parsed_data = json.loads(response_body)
                except (json.JSONDecodeError, ValueError):
                    parsed_data = response_body
                
                enrichment_results[f'source_{idx}'] = {
                    'url': url,
                    'status': status_code,
                    'content_type': content_type,
                    'data': parsed_data
                }
                
        except urllib.error.HTTPError as e:
            errors.append({
                'url': url,
                'error': f'HTTP Error: {e.code}',
                'reason': str(e.reason)
            })
        except urllib.error.URLError as e:
            errors.append({
                'url': url,
                'error': f'URL Error: {str(e.reason)}'
            })
        except Exception as e:
            errors.append({
                'url': url,
                'error': f'Unexpected error: {str(e)}'
            })
    
    # Build the enrichment payload
    enrichment_payload = {
        'enriched': True,
        'sources_requested': len(enrich_urls),
        'sources_succeeded': len(enrichment_results),
        'sources_failed': len(errors),
        'results': enrichment_results
    }
    
    if errors:
        enrichment_payload['errors'] = errors
    
    # Serialize and encode the enrichment data
    enrichment_json = json.dumps(enrichment_payload, default=str)
    
    # Base64 encode to safely pass in headers (avoid header value issues)
    enrichment_encoded = base64.b64encode(enrichment_json.encode('utf-8')).decode('ascii')
    
    # Lambda@Edge has header size limits (~8KB for viewer request)
    # Truncate if necessary
    max_header_size = 7680  # Leave some room under the 8KB limit
    
    if len(enrichment_encoded) > max_header_size:
        # If too large, send a truncated summary instead
        summary_payload = {
            'enriched': True,
            'truncated': True,
            'sources_requested': len(enrich_urls),
            'sources_succeeded': len(enrichment_results),
            'sources_failed': len(errors),
            'message': 'Enrichment data exceeded header size limit'
        }
        
        # Include as much data as possible from each source
        compact_results = {}
        for key, result in enrichment_results.items():
            data = result.get('data', '')
            if isinstance(data, dict):
                # Take only top-level keys with simple values
                compact_data = {
                    k: v for k, v in data.items()
                    if isinstance(v, (str, int, float, bool)) and len(str(v)) < 200
                }
            elif isinstance(data, str):
                compact_data = data[:200]
            else:
                compact_data = str(data)[:200]
            
            compact_results[key] = {
                'url': result['url'],
                'status': result['status'],
                'data': compact_data
            }
        
        summary_payload['results'] = compact_results
        enrichment_json = json.dumps(summary_payload, default=str)
        enrichment_encoded = base64.b64encode(enrichment_json.encode('utf-8')).decode('ascii')
    
    # Add enrichment data as a new header for the origin
    request['headers']['x-enrichment-data'] = [{
        'key': 'X-Enrichment-Data',
        'value': enrichment_encoded
    }]
    
    # Add a simple status header
    request['headers']['x-enrichment-status'] = [{
        'key': 'X-Enrichment-Status',
        'value': f'success:{len(enrichment_results)},failed:{len(errors)}'
    }]
    
    # Add individual enrichment results as separate headers for easy access
    for idx, (source_key, result) in enumerate(enrichment_results.items()):
        data = result.get('data', '')
        
        # For simple string/JSON values, add as individual headers
        if isinstance(data, dict):
            # Flatten top-level keys into headers
            for data_key, data_value in data.items():
                if isinstance(data_value, (str, int, float, bool)):
                    safe_key = data_key.lower().replace(' ', '-').replace('_', '-')
                    header_name = f'x-enrich-{idx}-{safe_key}'
                    header_value = str(data_value)[:512]  # Limit individual header size
                    
                    request['headers'][header_name] = [{
                        'key': f'X-Enrich-{idx}-{safe_key}',
                        'value': header_value
                    }]
        elif isinstance(data, str) and len(data) <= 512:
            request['headers'][f'x-enrich-{idx}-value'] = [{
                'key': f'X-Enrich-{idx}-Value',
                'value': data
            }]
    
    # Remove the original enrichment URL header to avoid leaking internal URLs to origin
    if enrich_header_key in request['headers']:
        del request['headers'][enrich_header_key]
    
    return request